    CTFSubmission = apps.get_model("ctf", "CTFSubmission")
    CTFHintUsage = apps.get_model("ctf", "CTFHintUsage")

    # Create CTFHint records from legacy challenge.hint fields
    for challenge in CTFChallenge.objects.filter(hint__gt="").exclude(hint=None):
        hint = CTFHint.objects.create(
            challenge=challenge,
            text=challenge.hint,
            penalty=challenge.hint_penalty,
            order=0,
        )

        # Create CTFHintUsage for each participant who used the hint
        # (deduplicate by participant since multiple submissions may have hint_used=True)
        participant_ids = (
            CTFSubmission.objects.filter(
                challenge=challenge,
                hint_used=True,
            )
            .values_list("participant_id", flat=True)
            .distinct()
        )
        for pid in participant_ids:
            CTFHintUsage.objects.create(
                participant_id=pid,
                hint=hint,
            )


